export const glossary: GlossaryTerm[] = [
  { term: 'Foundation Model', definition: 'A large model trained on broad data that serves as the basis for adaptation to many downstream tasks.' },
  { term: 'Generative AI', definition: 'AI systems that create new content (text, images, audio, code) rather than classifying or predicting existing data.' },
  { term: 'Scaling Laws', definition: 'Empirical relationships predicting model performance as a function of scale in parameters, data, and compute.' },
  { term: 'Mixture of Experts', definition: 'An architecture activating different subsets of parameters for different inputs, achieving large capacity with lower per-input cost.' },
  { term: 'RAG', definition: 'Retrieval-Augmented Generation, combining LLM generation with external knowledge retrieval to improve accuracy and reduce hallucination.' },
  { term: 'LoRA', definition: 'Low-Rank Adaptation, an efficient fine-tuning method that adds small trainable matrices to frozen model weights.' },
  { term: 'RLHF', definition: 'Reinforcement Learning from Human Feedback, used to align model behavior with human preferences.' },
  { term: 'AI Governance', definition: 'The policies, standards, and processes that direct and control how AI systems are developed, deployed, and monitored.' },
  { term: 'EU AI Act', definition: 'The European Union\'s comprehensive risk-based AI regulation establishing requirements proportional to potential harm.' },
  { term: 'Model Card', definition: 'Structured documentation reporting a model\'s intended use, performance characteristics, limitations, and ethical considerations.' },
  { term: 'Red-Teaming', definition: 'Structured adversarial testing of AI systems to discover failure modes, harmful outputs, and safety vulnerabilities before deployment.' },
  { term: 'Constitutional AI', definition: 'An alignment approach where the model critiques and revises its own outputs based on a written set of principles.' },
  { term: 'Algorithmic Bias', definition: 'Systematic errors in ML systems that produce unfair outcomes for particular groups, arising from data, modeling, or deployment choices.' },
  { term: 'SHAP', definition: 'SHapley Additive exPlanations, an explainability method based on Shapley values that decomposes predictions into per-feature contributions.' },
  { term: 'Responsible Scaling Policy', definition: 'A governance framework linking model capability levels to required safety evaluations and containment measures.' },
  { term: 'Datasheets for Datasets', definition: 'Standardized documentation for ML datasets recording motivation, composition, collection process, and intended uses.' },
];

